#include<bits/stdc++.h>
using namespace std;
int n,x,k;
bool f(int a){
	int ans=0,v=x;
	for (int i=1;i<=n;i++){
		if(abs((a%10)-(v%10))==1||abs((a%10)-(v%10))==9)ans++;
		else if(abs((v%10)-(a%10))>=2)return false;
		v/=10,a/=10;
	}
	return ans<=k;
}
int main(void){
	cin>>n>>x>>k;
	for(int i=0;i<pow(10,n);i++){
		if(f(i))cout<<i<<endl; 
	}
	return false;
}
